SELECT DISTINCT m.id, m.parent_id, m.menu_name, m.menu_type, m.route_path, m.component_path, m.permission_code, m.sort_no FROM szzw.t_yqyc_sys_menu m JOIN szzw.t_yqyc_sys_role_menu rm ON m.id = rm.menu_id JOIN szzw.t_yqyc_sys_role r ON rm.role_id = r.id WHERE r.role_code IN
#{code}
AND m.status = '启用' AND m.menu_type IN ('目录', '菜单') ORDER BY m.sort_no ASC

SELECT DISTINCT m.permission_code FROM szzw.t_yqyc_sys_menu m JOIN szzw.t_yqyc_sys_role_menu rm ON m.id = rm.menu_id JOIN szzw.t_yqyc_sys_role r ON rm.role_id = r.id WHERE r.role_code IN
#{code}
AND m.status = '启用' AND m.permission_code IS NOT NULL
